<?php
require_once dirname(__DIR__) . '/includes/cms.php';
$pdo=obtenerConexion();$seccionId=cmsId($_GET['seccion_id']??0);$pagina=max(1,cmsId($_GET['pagina']??1));$porPagina=20;$offset=($pagina-1)*$porPagina;$secciones=$pdo->query('SELECT id,nombre FROM secciones ORDER BY orden,id')->fetchAll();
$where=$seccionId?'WHERE e.seccion_id=:sid':'';$conteo=$pdo->prepare("SELECT COUNT(*) FROM elementos_seccion e $where");$conteo->execute($seccionId?['sid'=>$seccionId]:[]);$total=(int)$conteo->fetchColumn();$q=$pdo->prepare("SELECT e.*,s.nombre seccion_nombre FROM elementos_seccion e JOIN secciones s ON s.id=e.seccion_id $where ORDER BY s.orden,e.orden,e.id LIMIT :limite OFFSET :offset");if($seccionId)$q->bindValue('sid',$seccionId,PDO::PARAM_INT);$q->bindValue('limite',$porPagina,PDO::PARAM_INT);$q->bindValue('offset',$offset,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();
cmsCabecera('Elementos de las secciones','elementos/index.php','Administra tarjetas, cifras, áreas y capacitaciones. Las noticias tienen un módulo editorial propio.');
